import{_ as e,c as r}from"./app.56afa649.js";const t={},a=r('<h1 id="regler" tabindex="-1"><a class="header-anchor" href="#regler" aria-hidden="true">#</a> Regler</h1><p>\xA71. Staffs ord g\xE4ller oavsett.</p><ul><li><em>Det g\xE4ller att lyssna p\xE5 vad staff s\xE4ger \xE4ven om man inte h\xE5ller med.</em></li></ul><hr><p>\xA72. Ett gott uppf\xF6rande.</p><ul><li><em>Vi spelar tillsammans och vi \xE4r v\xE4nliga mot varandra. Hot, trackaserrier, mobbning \xE4r inte till\xE5tet.</em></li></ul><hr><p>\xA73. Buggar/Glitchar</p><ul><li><em>Det finns buggar och glitchar i Minecraft, dessa ska inte utnytjas f\xF6r egen vinning.</em></li></ul><hr><p>\xA74. Ingen reklam tack!</p><ul><li><em>Vi vill inte att man g\xF6r reklam, varken f\xF6r andra servrar, discord, youtubekanaler eller n\xE5got.</em></li></ul><hr><p>\xA75. Undvik inte AFK systemet.</p><ul><li><em>AFK systemet finns av en anledning och ska inte undvikas.</em></li></ul><hr><p>\xA76. Griefing \xE4r inte till\xE5tet.</p><ul><li><em>Griefing \xE4r till\xE5tet i ett oskyddat omr\xE5de MEN kom ih\xE5g vad griefing inneb\xE4r.<br> &quot;En griefer \xE4r en spelare som utf\xF6r handlingar i ett datorspel f\xF6r att avsiktligt<br> besv\xE4ra en annan spelare (&quot;grief&quot; i betydelsen orsaka n\xE5gon \u201Dsorg\u201D f\xF6r sitt eget n\xF6jes skull.&quot;<br> Med andra ord om vi anser att syftet \xE4r f\xF6r att f\xF6rst\xF6ra s\xE5 r\xE4knar vi det som griefing oavsett om omr\xE5det \xE4r skyddat eller inte.</em></li></ul><hr><p>\xA77. Anv\xE4nd ett v\xE5rdat spr\xE5k.</p><ul><li><em>Vi har ett v\xE5rdat spr\xE5k, det \xE4r m\xE5nga yngre som spelar h\xE4r och d\xE4rf\xF6r h\xE5ller vi en niv\xE5 som \xE4r l\xE4mplig f\xF6r alla.</em></li></ul><hr><p>\xA78. Skapa inte lagg.</p><ul><li><em>Bygg inte maskiner / lagringsystem / farmer eller annat som orsakar lagg p\xE5 servern.</em></li></ul><hr><p>\xA79. Tjata inte.</p><ul><li><em>Att tjata p\xE5 staff eller p\xE5 andra spelare f\xF6r att f\xE5 det man vill \xE4r inget vi sysslar med.</em></li></ul><hr><p>\xA710. Fuska inte! Fuska aldrig!</p><ul><li><em>Klienter, moddar, autoklickers, bottar, &quot;cointrick&quot; \xE4r inte till\xE5tet.<br> Det finns <em>vissa undantag</em> som tex optifine. \xC4r du os\xE4ker s\xE5 fr\xE5ga.<br> &quot;Cointrick betyder att man s\xE4tter ett mynt p\xE5 en tangent f\xF6r att tex sl\xE5 automatiskt.<br> Liknande l\xF6sningar med samma resultat r\xE4knas ocks\xE5 som cointrick&quot;</em></li></ul>',30);function i(l,n){return a}var m=e(t,[["render",i],["__file","regler.html.vue"]]);export{m as default};
